1772806343183.newValue:
() => {
  const storedDate = tools.getCtData("sc.a4.editData.product.date");

  // Força extrair sempre uma string
  let dateValue = "";
  if (Array.isArray(storedDate)) {
    dateValue = storedDate[0] || "";
  } else if (typeof storedDate === "string") {
    dateValue = storedDate;
  }

  const inputStyle = {
    paddingTop: "4px",
    paddingBottom: "4px",
    paddingLeft: "14px",
    paddingRight: "36px",
    borderRadius: "6px",
    border: "1px solid #E6E7E8",
    boxShadow: "0 1px 2px rgba(0,0,0,0.05)",
    transition: "all 0.2s",
    color: "#374151",
    backgroundColor: "#fff",
    outline: "none",
    width: "150px",
    height: "32px"
  };

  const wrapperStyle = {
    position: "relative",
    width: "fit-content"
  };

  const iconStyle = {
    position: "absolute",
    right: "12px",
    top: "50%",
    transform: "translateY(-50%)",
    color: "#9ca3af",
    pointerEvents: "none"
  };

  return (
    <div style={wrapperStyle}>
      <input
        type="date"
        value={dateValue}
        onChange={(e) => {
          const selectedDate = e.target.value;

          tools.functions.setVar({
            args: "",
            pass: {
              keyPath: ["sc.a4.editData.product.date"],
              value: [selectedDate]
            }
          });

          console.log("📅 Data escolhida:", selectedDate);
        }}
        style={inputStyle}
      />
      <span style={iconStyle}></span>
